package aula03.exercicio1_completo.application;import aula03.exercicio1_completo.entities.Aluno;import java.util.Scanner;public class Program {    private Aluno aluno;    public void entradaAluno(){        Scanner sc = new Scanner(System.in);        System.out.println("---- CADASTRO DO ALUNO ----");        System.out.print("Codigo: ");        int alu_codigo = sc.nextInt();        sc.nextLine();        System.out.print("CPF: ");        String alu_cpf = sc.nextLine();        System.out.print("RG: ");        String alu_rg = sc.nextLine();        System.out.print("Nome: ");        String alu_nome = sc.nextLine();        System.out.print("Endereço: ");        String alu_endereco = sc.nextLine();        System.out.print("Numero: ");        int alu_numero = sc.nextInt();        sc.nextLine();        System.out.print("Complemento: ");        String alu_complemento = sc.nextLine();        System.out.print("Bairro: ");        String alu_bairro = sc.nextLine();        System.out.print("Cidade: ");        String alu_cidade = sc.nextLine();        System.out.print("Estado: ");        String alu_estado = sc.nextLine();        System.out.print("Telefone: ");        String alu_telefone = sc.nextLine();        System.out.print("Celular: ");        String alu_celular = sc.nextLine();        System.out.print("Email: ");        String alu_email = sc.nextLine();        System.out.print("Salario: ");        double alu_salario = sc.nextDouble();        System.out.print("Sexo (M/F): ");        char sexo = sc.next().toUpperCase().trim().charAt(0);        boolean alu_masculino = (sexo == 'M');     aluno = new Aluno(alu_codigo, alu_cpf, alu_rg, alu_nome, alu_endereco,                alu_numero, alu_complemento, alu_bairro, alu_cidade, alu_estado,                alu_telefone, alu_celular, alu_email, alu_salario, alu_masculino);    }    public void imprimeAluno(){       System.out.println(aluno);    }    static void main() {        Program program = new Program();        program.entradaAluno();        program.imprimeAluno();    }}